const data = items[0].json;

// 🔹 Nome
const nomeUsuario = data.nome || "";

// 🔹 Contexto
const contexto = data.contexto || "";

// 🔹 Resultados
const resultados = data.resultados || [];

// 🔹 Ordenação
const ordenados = resultados.sort((a, b) => b.item.nota - a.item.nota);

// 🔹 Top 2
const top2 = ordenados.slice(0, 2);

// 🔹 Telefone simples
const formatarTelefone = (tel) => {
  if (!tel) return "";
  const partes = tel.replace(/[()]/g, "").split(" ");
  return partes.slice(0, 2).join(" ");
};

// 🔹 Limpar site
const limparSite = (url) => {
  if (!url) return "";
  return url
    .replace("https://", "")
    .replace("http://", "")
    .replace("www.", "")
    .replace(/\/$/, "");
};

// 🔹 Montar lista
const fornecedoresTexto = top2.map(f => {
  const item = f.item;

  const nome = item.razao_social;
  const site = limparSite(item.site);
  const telefone = formatarTelefone(item.telefone);

  let extra = "";

  if (site) extra += site;
  if (telefone) extra += (extra ? ", " : "") + telefone;

  return `- ${nome} (${extra})`;
});

// 🔹 Mensagem
let mensagem = "";

// Saudação
mensagem += nomeUsuario ? `Oi, ${nomeUsuario}, tudo bem?\n\n` : `Oi, tudo bem?\n\n`;

// Contexto
if (contexto) {
  mensagem += `Vi sua mensagem no grupo sobre ${contexto} e te mandei esses dois que podem fazer sentido:\n`;
} else {
  mensagem += `Vi sua mensagem no grupo e indico esses dois fornecedores que podem fazer sentido:\n`;
}

// Lista
mensagem += fornecedoresTexto.join("\n") + "\n\n";

// CTA
mensagem += `Se quiser ver mais opções, deixei essa busca pronta aqui:\n`;
mensagem += `https://buscafornecedor.com.br/\n\n`;

mensagem += `É só entrar com esse número e você já acessa tudo.`;


return [
  {
    json: {
      mensagem
    }
  }
];

